```python
@contextmanager
def profiling(transaction, hub=None):
    # type: (Transaction, Optional[sentry_sdk.Hub]) -> Generator[None, None, None]
    if hub is None:
        hub = sentry_sdk.Hub.current
    if hub.client.options["enable_profiling"]:
        with Sampler(transaction):
            yield
    else:
        yield
```

